import { test, assert, assertEqual } from './helpers';
import { ThemeService } from '../../src/app/kree/services/theme.service';

test('ThemeService: starts dark when no system preference and no stored value', () => {
  (global as any).localStorage.clear();
  (global as any).window.matchMedia = () => ({ matches: false });
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'dark');
  assertEqual((global as any).__attrs.get('data-theme'), 'dark');
});

test('ThemeService: starts light when system prefers light and no stored value', () => {
  (global as any).localStorage.clear();
  (global as any).window.matchMedia = (q: string) =>
    q.includes('light') ? { matches: true } : { matches: false };
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'light');
});

test('ThemeService: respects a previously-stored light preference', () => {
  (global as any).localStorage.setItem('kree.theme', 'light');
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'light');
});

test('ThemeService: respects a previously-stored dark preference', () => {
  (global as any).localStorage.setItem('kree.theme', 'dark');
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'dark');
});

test('ThemeService: ignores a garbage stored value', () => {
  (global as any).localStorage.setItem('kree.theme', 'chartreuse');
  (global as any).window.matchMedia = () => ({ matches: false });
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'dark');
});

test('ThemeService: toggle flips dark→light and persists', () => {
  (global as any).localStorage.clear();
  const svc = new ThemeService();
  svc.init();
  svc.toggle();
  assertEqual(svc.theme(), 'light');
  assertEqual((global as any).localStorage.getItem('kree.theme'), 'light');
});

test('ThemeService: toggle flips light→dark', () => {
  (global as any).localStorage.setItem('kree.theme', 'light');
  const svc = new ThemeService();
  svc.init();
  svc.toggle();
  assertEqual(svc.theme(), 'dark');
});

test('ThemeService: set() applies mode directly', () => {
  const svc = new ThemeService();
  svc.set('light');
  assertEqual(svc.theme(), 'light');
  svc.set('dark');
  assertEqual(svc.theme(), 'dark');
});

test('ThemeService: set() survives localStorage exceptions', () => {
  const origLS = (global as any).localStorage;
  (global as any).localStorage = {
    getItem: () => { throw new Error('boom'); },
    setItem: () => { throw new Error('boom'); },
  };
  const svc = new ThemeService();
  svc.init(); // readStored() throws → falls through to matchMedia/default
  svc.set('light');
  assertEqual(svc.theme(), 'light');
  (global as any).localStorage = origLS;
});

test('ThemeService: init() survives when window is missing matchMedia', () => {
  const realWindow = (global as any).window;
  (global as any).window = {};
  (global as any).localStorage.clear();
  const svc = new ThemeService();
  svc.init();
  assertEqual(svc.theme(), 'dark');
  (global as any).window = realWindow;
});

// Test helpers shared by every unit test file.
//
// `test()` is a minimal wrapper around the registry installed on
// `global.__registerTest` by unit-runner.cjs. Tests run sequentially
// and can await promises (for the `setTimeout` chains inside Kree
// components we use `flushTimers`).

declare const __registerTest: (name: string, fn: () => void | Promise<void>) => void;

export function test(name: string, fn: () => void | Promise<void>): void {
  __registerTest(name, fn);
}

export function assert(cond: any, msg = 'assertion failed'): void {
  if (!cond) {
    throw new Error(msg);
  }
}

export function assertEqual<T>(actual: T, expected: T, msg?: string): void {
  if (actual !== expected) {
    throw new Error(
      `${msg || 'values differ'}: expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`,
    );
  }
}

/** Fast-forward pending setTimeout chains. We replace real timers
 *  with a deterministic fake so tests don't sleep for real seconds. */
export function installFakeTimers() {
  const queue: Array<{ id: number; when: number; fn: () => void }> = [];
  let now = 0;
  let nextId = 1;
  const realSetTimeout = global.setTimeout;
  const realClearTimeout = global.clearTimeout;

  (global as any).setTimeout = (fn: () => void, ms: number) => {
    const id = nextId++;
    queue.push({ id, when: now + (ms || 0), fn });
    queue.sort((a, b) => a.when - b.when);
    return id as any;
  };
  (global as any).clearTimeout = (id: number) => {
    const idx = queue.findIndex((q) => q.id === id);
    if (idx >= 0) queue.splice(idx, 1);
  };
  (global as any).setInterval = (global as any).setTimeout;
  (global as any).clearInterval = (global as any).clearTimeout;

  return {
    advance(ms: number) {
      const target = now + ms;
      while (queue.length && queue[0].when <= target) {
        const item = queue.shift()!;
        now = item.when;
        item.fn();
      }
      now = target;
    },
    runAll(maxSteps = 10000) {
      let steps = 0;
      while (queue.length && steps < maxSteps) {
        const item = queue.shift()!;
        now = item.when;
        item.fn();
        steps++;
      }
      if (queue.length) {
        throw new Error('fake-timer queue did not drain');
      }
    },
    queue,
    uninstall() {
      (global as any).setTimeout = realSetTimeout;
      (global as any).clearTimeout = realClearTimeout;
    },
  };
}

import { Injectable, signal } from '@angular/core';

export type ThemeMode = 'dark' | 'light';

const STORAGE_KEY = 'kree.theme';

@Injectable({ providedIn: 'root' })
export class ThemeService {
  readonly theme = signal<ThemeMode>('dark');

  init(): void {
    // Respect a previously-saved preference, else honour the system.
    const stored = this.readStored();
    if (stored) {
      this.apply(stored);
      return;
    }
    const prefersLight =
      typeof window !== 'undefined' &&
      window.matchMedia &&
      window.matchMedia('(prefers-color-scheme: light)').matches;
    this.apply(prefersLight ? 'light' : 'dark');
  }

  toggle(): void {
    this.apply(this.theme() === 'dark' ? 'light' : 'dark');
  }

  set(mode: ThemeMode): void {
    this.apply(mode);
  }

  private apply(mode: ThemeMode): void {
    this.theme.set(mode);
    if (typeof document !== 'undefined') {
      document.documentElement.setAttribute('data-theme', mode);
    }
    try {
      localStorage?.setItem(STORAGE_KEY, mode);
    } catch {
      /* storage unavailable — fine, we'll use defaults next boot */
    }
  }

  private readStored(): ThemeMode | null {
    try {
      const v = localStorage?.getItem(STORAGE_KEY);
      return v === 'dark' || v === 'light' ? v : null;
    } catch {
      return null;
    }
  }
}

import { test, assert, assertEqual, installFakeTimers } from './helpers';
import { ThisMomentComponent } from '../../src/app/kree/this-moment/this-moment.component';

test('ThisMoment: sets isMobile=true when viewport is narrow', () => {
  const timers = installFakeTimers();
  const realW = (global as any).window.innerWidth;
  (global as any).window.innerWidth = 320;
  const c = new ThisMomentComponent();
  c.ngOnInit();
  assertEqual(c.isMobile, true);
  (global as any).window.innerWidth = realW;
  c.ngOnDestroy();
  timers.uninstall();
});

test('ThisMoment: leaves isMobile=false on a wide viewport', () => {
  const timers = installFakeTimers();
  (global as any).window.innerWidth = 1200;
  const c = new ThisMomentComponent();
  c.ngOnInit();
  assertEqual(c.isMobile, false);
  c.ngOnDestroy();
  timers.uninstall();
});

test('ThisMoment: isMobile is left alone when window.innerWidth is undefined', () => {
  const timers = installFakeTimers();
  const realWindow = (global as any).window;
  (global as any).window = undefined;
  const c = new ThisMomentComponent();
  c.ngOnInit();
  assertEqual(c.isMobile, false);
  c.ngOnDestroy();
  (global as any).window = realWindow;
  timers.uninstall();
});

test('ThisMoment: Pause → Take a breath → ready sequence advances on timers', () => {
  const timers = installFakeTimers();
  const c = new ThisMomentComponent();
  c.ngOnInit();

  assertEqual(c.begin, false);
  assertEqual(c.breathe, 'in');

  timers.advance(1500);
  assertEqual(c.begin, true);

  timers.advance(2000);
  assertEqual(c.paused, true);
  assertEqual(c.breathe, 'out');

  timers.advance(2000);
  assertEqual(c.ready, true);
  // Breathing continues (does not go to idle)
  assertEqual(c.breathe, 'in');
  c.ngOnDestroy();
  timers.uninstall();
});

test('ThisMoment: next() sets showCta=true and emits answered', () => {
  const timers = installFakeTimers();
  const c = new ThisMomentComponent();
  c.ngOnInit();
  let emitted: boolean | undefined;
  c.answered.subscribe((v: boolean) => { emitted = v; });
  c.next();
  assertEqual(c.showCta, true);
  assertEqual(emitted, true);
  c.ngOnDestroy();
  timers.uninstall();
});

test('ThisMoment: flow resets after 10 seconds of CTA visibility', () => {
  const timers = installFakeTimers();
  const c = new ThisMomentComponent();
  c.ngOnInit();

  // Advance to ready state
  timers.advance(5500);
  assertEqual(c.ready, true);

  // Trigger CTA
  c.next();
  assertEqual(c.showCta, true);

  // After 10 seconds, flow resets
  timers.advance(10000);
  assertEqual(c.showCta, false);
  assertEqual(c.ready, false);
  assertEqual(c.begin, false);
  assertEqual(c.breathe, 'in'); // restarted

  c.ngOnDestroy();
  timers.uninstall();
});

test('ThisMoment: ngOnDestroy clears pending timers without firing them', () => {
  const timers = installFakeTimers();
  const c = new ThisMomentComponent();
  c.ngOnInit();
  c.ngOnDestroy();
  timers.advance(10000);
  // If ngOnDestroy failed to clear, `begin`/`paused`/`ready` would flip.
  assertEqual(c.begin, false);
  assertEqual(c.paused, false);
  assertEqual(c.ready, false);
  timers.uninstall();
});

import {
  Component,
  EventEmitter,
  OnDestroy,
  OnInit,
  Output,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { QuestionComponent } from '../question/question.component';

@Component({
  selector: 'this-moment',
  standalone: true,
  imports: [CommonModule, QuestionComponent],
  templateUrl: './this-moment.component.html',
  styleUrls: ['./this-moment.component.css'],
})
export class ThisMomentComponent implements OnInit, OnDestroy {
  public firstAnswered = false;
  public secondAnswered = false;
  public isMobile = false;

  public begin = false;
  public paused = false;
  public ready = false;
  public showCta = false;

  /** drives the breathe-in / breathe-out visual — loops continuously */
  public breathe: 'in' | 'out' | 'idle' = 'idle';

  @Output() answered = new EventEmitter<boolean>();

  private timers: any[] = [];
  private resetTimer: any = null;

  ngOnInit(): void {
    if (typeof window !== 'undefined' && window.innerWidth < 768) {
      this.isMobile = true;
    }

    this.startSequence();
  }

  ngOnDestroy(): void {
    this.timers.forEach((t) => clearTimeout(t));
    this.timers = [];
    if (this.resetTimer) clearTimeout(this.resetTimer);
  }

  private startSequence(): void {
    // Start breathing immediately — runs continuously
    this.breathe = 'in';

    this.timers.push(
      setTimeout(() => {
        this.begin = true;

        this.timers.push(
          setTimeout(() => {
            this.paused = true;
            this.breathe = 'out';

            this.timers.push(
              setTimeout(() => {
                this.ready = true;
                // Keep breathing — alternate between in/out continuously
                this.breathe = 'in';
              }, 2000),
            );
          }, 2000),
        );
      }, 1500),
    );
  }

  next(): void {
    // Show CTA, questions stay visible
    this.showCta = true;
    this.answered.emit(true);

    // After 10 seconds of CTA visibility, reset the entire flow
    this.resetTimer = setTimeout(() => this.resetFlow(), 10000);
  }

  private resetFlow(): void {
    // Clear everything
    this.timers.forEach((t) => clearTimeout(t));
    this.timers = [];

    // Reset state
    this.firstAnswered = false;
    this.secondAnswered = false;
    this.begin = false;
    this.paused = false;
    this.ready = false;
    this.showCta = false;
    this.breathe = 'idle';

    // Restart the entire sequence
    this.startSequence();
  }
}

import {
  Component,
  EventEmitter,
  Input,
  OnDestroy,
  OnInit,
  Output,
} from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'question',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './question.component.html',
  styleUrls: ['./question.component.scss'],
})
export class QuestionComponent implements OnInit, OnDestroy {
  @Input() q = '';
  @Input() answer = '';
  @Output() answered = new EventEmitter<boolean>();

  public label = '';
  public prompt = false;
  public showAnswer = false;
  public hasAnswered = false;

  private readonly startInterval = 1000;
  private readonly promptInterval = 3000;
  private readonly typeInterval = 100;
  private readonly markInterval = 500;
  private readonly markMax = 3;
  private markCounter = 0;

  private timers: any[] = [];

  ngOnInit(): void {
    this.label = '';
    this.markCounter = 0;
    this.showAnswer = false;
    this.hasAnswered = false;
    this.prompt = false;

    this.timers.push(
      setTimeout(() => this.showNextChar(), this.startInterval),
    );
  }

  ngOnDestroy(): void {
    this.timers.forEach((t) => clearTimeout(t));
    this.timers = [];
  }

  toggleQuestionMark(): void {
    if (this.label.charAt(this.label.length - 1) === '?') {
      this.label = this.label.substring(0, this.label.length - 1);
      this.timers.push(
        setTimeout(() => this.toggleQuestionMark(), this.markInterval),
      );
      return;
    }

    this.label += '?';
    this.markCounter++;
    if (this.markCounter < this.markMax) {
      this.timers.push(
        setTimeout(() => this.toggleQuestionMark(), this.markInterval),
      );
    } else {
      this.showAnswer = true;
      this.timers.push(
        setTimeout(() => {
          this.prompt = true;
          this.timers.push(setTimeout(() => this.onClick(), 1500));
        }, this.promptInterval),
      );
    }
  }

  onClick(): void {
    if (this.hasAnswered) {
      return;
    }
    this.hasAnswered = true;
    this.answered.emit(true);
  }

  showNextChar(): void {
    if (this.label.length !== this.q.length) {
      this.label = this.q.substring(0, this.label.length + 1);
      this.timers.push(
        setTimeout(() => this.showNextChar(), this.typeInterval),
      );
    } else {
      this.toggleQuestionMark();
    }
  }
}

import { test, assert, assertEqual, installFakeTimers } from './helpers';
import { QuestionComponent } from '../../src/app/kree/question/question.component';

test('Question: types out q one character at a time', () => {
  const timers = installFakeTimers();
  const c = new QuestionComponent();
  c.q = 'Hi';
  c.answer = 'Y';
  c.ngOnInit();

  timers.advance(1000);                 // startInterval
  assertEqual(c.label, 'H');
  timers.advance(100);                  // typeInterval
  assertEqual(c.label, 'Hi');
  c.ngOnDestroy();
  timers.uninstall();
});

test('Question: pulses three question marks after typing', () => {
  const timers = installFakeTimers();
  const c = new QuestionComponent();
  c.q = 'Hi';
  c.answer = 'Y';
  c.ngOnInit();
  timers.advance(1000);
  timers.advance(100);
  // First toggle: append "?"
  timers.advance(100);                  // triggers toggleQuestionMark
  // Walk the 3 toggle cycles
  timers.advance(500);
  timers.advance(500);
  timers.advance(500);
  timers.advance(500);
  timers.advance(500);
  timers.advance(500);
  assertEqual(c.showAnswer, true);
  c.ngOnDestroy();
  timers.uninstall();
});

test('Question: auto-emits answered after full pulse + prompt + 1.5s', () => {
  const timers = installFakeTimers();
  const c = new QuestionComponent();
  c.q = 'A';
  c.answer = 'B';
  c.ngOnInit();
  let fired: boolean | undefined;
  c.answered.subscribe((v: boolean) => { fired = v; });
  timers.runAll();
  assertEqual(fired, true);
  assertEqual(c.hasAnswered, true);
  timers.uninstall();
});

test('Question: manual onClick() short-circuits the auto-answer', () => {
  const timers = installFakeTimers();
  const c = new QuestionComponent();
  c.q = 'A';
  c.answer = 'B';
  c.ngOnInit();
  let count = 0;
  c.answered.subscribe(() => { count++; });
  c.onClick();
  assertEqual(c.hasAnswered, true);
  // A second click and the eventual auto-fire should both be ignored.
  c.onClick();
  timers.runAll();
  assertEqual(count, 1);
  timers.uninstall();
});

import { test, assert, assertEqual, installFakeTimers } from './helpers';
import { YourNameComponent } from '../../src/app/kree/your-name/your-name.component';

function makeElementRef() {
  const fakeInput = { focus: () => { (fakeInput as any).focused = true; } };
  return {
    nativeElement: {
      querySelector: (sel: string) => (sel === '.yourName' ? fakeInput : null),
    },
    _input: fakeInput,
  };
}

test('YourName: cycles through every "I"-script and then shows the input', () => {
  const timers = installFakeTimers();
  const el = makeElementRef();
  const c = new YourNameComponent(el as any);
  c.ngOnInit();
  // Each letter takes two 1-second beats; there are 5 letters.
  timers.advance(500);           // initial delay -> first nextMeText()
  for (let i = 0; i < 5; i++) {
    timers.advance(1000);        // enter -> exit flip
    timers.advance(1000);        // exit -> next call
  }
  timers.advance(500);           // inputVisible gate
  timers.advance(1000);          // focus callback
  assertEqual(c.inputVisible, true);
  assertEqual(c.inputWidth, 300);
  assertEqual(c.currentMe, c.mes.length - 1);
  assertEqual((el._input as any).focused, true);
  c.ngOnDestroy();
  timers.uninstall();
});

test('YourName: moveOn() sets hasName=true and starts typeaway for "am here now"', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  let emitCount = 0;
  c.answered.subscribe(() => { emitCount++; });
  c.moveOn();
  assertEqual(c.hasName, true);
  assertEqual(c.showAmHereNow, true);
  // Type "am here now." (12 chars) at 100ms each + 500ms initial delay + 500ms after done
  timers.advance(500);  // initial delay before typing
  timers.advance(1200); // 12 chars at 100ms
  timers.advance(500);  // delay after done
  assertEqual(emitCount, 1);
  // calling moveOn again should be idempotent
  c.moveOn();
  assertEqual(emitCount, 1);
  timers.uninstall();
});

test('YourName: checkName(key) schedules moveOn() when name settles', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.name = 'Ada';
  c.checkName(new (globalThis as any).Object() as any);
  timers.advance(3000);
  assertEqual(c.hasName, true);
  timers.uninstall();
});

test('YourName: checkName(key) does NOT fire when the name keeps changing', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.name = 'Ad';
  c.checkName({} as any);
  c.name = 'Ada'; // user is still typing
  timers.advance(3000);
  assertEqual(c.hasName, false);
  timers.uninstall();
});

test('YourName: checkName() ignores an empty value', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.name = '';
  c.checkName({} as any);
  timers.advance(3000);
  assertEqual(c.hasName, false);
  timers.uninstall();
});

test('YourName: onNameInput resizes input based on name length', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.name = 'Ada Lovelace';
  c.onNameInput();
  assert(c.inputWidth > 60, 'input width should grow with name');
  assert(c.inputWidth <= 500, 'input width should cap at 500');
  timers.uninstall();
});

test('YourName: empty name resets input width to 300', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.name = '';
  c.onNameInput();
  assertEqual(c.inputWidth, 300);
  timers.uninstall();
});

test('YourName: ngOnDestroy clears pending timers', () => {
  const timers = installFakeTimers();
  const c = new YourNameComponent(makeElementRef() as any);
  c.ngOnInit();
  c.ngOnDestroy();
  timers.advance(10000);
  assertEqual(c.currentMe, -1);
  timers.uninstall();
});

import {
  Component,
  ElementRef,
  EventEmitter,
  OnDestroy,
  OnInit,
  Output,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'your-name',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './your-name.component.html',
  styleUrls: ['./your-name.component.scss'],
})
export class YourNameComponent implements OnInit, OnDestroy {
  @Output() answered = new EventEmitter<void>();

  public name = '';
  public placeholder = 'Full Name';
  public meText = '';
  public mes: string[] = ['I', '\u092E\u0948\u0902', '\u0A2E\u0A48\u0A28\u0A42\u0A70', '\u0CA8\u0CBE\u0CA8\u0CC1', ' \u0645\u06CC\u06BA '];
  public currentMe = -1;

  public entering = false;
  public exiting = false;
  public hasName = false;
  public inputVisible = false;
  public inputWidth = 0;

  // Typeaway for "am here now."
  public amHereNowLabel = '';
  public showAmHereNow = false;

  private readonly showInterval = 1000;
  private timers: any[] = [];

  constructor(private el: ElementRef) {}

  ngOnInit(): void {
    this.timers.push(setTimeout(() => this.nextMeText(), 500));
  }

  ngOnDestroy(): void {
    this.timers.forEach((t) => clearTimeout(t));
    this.timers = [];
  }

  nextMeText(): void {
    if (this.currentMe < this.mes.length - 1) {
      this.exiting = false;
      this.entering = true;
      this.meText = this.mes[++this.currentMe];

      this.timers.push(
        setTimeout(() => {
          this.entering = false;
          this.exiting = true;

          this.timers.push(
            setTimeout(() => this.nextMeText(), this.showInterval),
          );
        }, this.showInterval),
      );
      return;
    }

    this.inputVisible = true;
    this.timers.push(
      setTimeout(() => {
        this.inputWidth = 300;
        this.timers.push(
          setTimeout(() => {
            const input =
              this.el?.nativeElement?.querySelector('.yourName') as HTMLInputElement | null;
            input?.focus();
          }, 1000),
        );
      }, 500),
    );
  }

  onNameInput(): void {
    this.resizeInput();
  }

  checkName(_key: KeyboardEvent | Event): void {
    this.resizeInput();
    const snapshot = this.name;
    this.timers.push(
      setTimeout(() => {
        if (snapshot === this.name && snapshot.trim().length > 0) {
          this.moveOn();
        }
      }, 3000),
    );
  }

  moveOn(): void {
    if (this.hasName) {
      return;
    }
    this.hasName = true;
    // Start typeaway for "am here now."
    this.showAmHereNow = true;
    this.typeAmHereNow();
  }

  private typeAmHereNow(): void {
    const fullText = 'am here now.';
    let idx = 0;
    const typeNext = () => {
      if (idx < fullText.length) {
        idx++;
        this.amHereNowLabel = fullText.substring(0, idx);
        const ch = fullText[idx - 1];
        const delay = ch === ',' ? 800 : 100;
        this.timers.push(setTimeout(typeNext, delay));
      } else {
        // Done typing — emit answered
        this.timers.push(setTimeout(() => this.answered.emit(), 500));
      }
    };
    this.timers.push(setTimeout(typeNext, 500));
  }

  private resizeInput(): void {
    if (!this.name) {
      this.inputWidth = 300;
      return;
    }
    // Approximate width: ~18px per character + padding, capped at 500
    const width = Math.max(60, this.name.length * 18 + 20);
    this.inputWidth = Math.min(width, 500);
  }
}

