import { test, assert, assertEqual } from './helpers';
import { LandingComponent } from '../../src/app/kree/landing/landing.component';

test('Landing: defaults beginPledge to false', () => {
  const c = new LandingComponent();
  assertEqual(c.beginPledge, false);
});

test('Landing: onAnswered sets beginPledge', () => {
  const c = new LandingComponent();
  c.onAnswered(true);
  assertEqual(c.beginPledge, true);
});

test('Landing: toggleTheme flips the theme', () => {
  const c = new LandingComponent();
  c.ngOnInit();
  const before = c.theme();
  c.toggleTheme();
  const after = c.theme();
  assert(before !== after, 'theme should flip');
});

import {
  Component,
  OnInit,
  OnDestroy,
  inject,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { ThisMomentComponent } from '../this-moment/this-moment.component';
import { ThemeService } from '../services/theme.service';

@Component({
  selector: 'kree-landing',
  standalone: true,
  imports: [CommonModule, ThisMomentComponent],
  templateUrl: './landing.component.html',
  styleUrls: ['./landing.component.css'],
})
export class LandingComponent implements OnInit, OnDestroy {
  public beginPledge = false;
  private readonly themeService = inject(ThemeService);
  public readonly theme = this.themeService.theme;
  private router = inject(Router);

  ngOnInit(): void {
    this.themeService.init();
  }

  ngOnDestroy(): void {}

  toggleTheme(): void {
    this.themeService.toggle();
  }

  onAnswered(val: boolean): void {
    this.beginPledge = val;
  }

  goToPledge(): void {
    this.router.navigate(['/pledge']);
  }
}

import { test, assert, assertEqual } from './helpers';
import { PledgePageComponent } from '../../src/app/kree/pledge-page/pledge-page.component';

function makeMocks() {
  const navigated: any[] = [];
  const location = { back: () => { (location as any).wentBack = true; }, wentBack: false };
  const router = {
    navigate: (cmds: any[]) => { navigated.push(cmds); return Promise.resolve(true); },
    _navigated: navigated,
  };
  return { location, router };
}

test('PledgePage: defaults pledgeComplete to false', () => {
  const { location, router } = makeMocks();
  const c = new PledgePageComponent(location as any, router as any);
  assertEqual(c.pledgeComplete, false);
});

test('PledgePage: onPledgeDone sets pledgeComplete', () => {
  const { location, router } = makeMocks();
  const c = new PledgePageComponent(location as any, router as any);
  c.onPledgeDone();
  assertEqual(c.pledgeComplete, true);
});

test('PledgePage: goBack calls location.back()', () => {
  const { location, router } = makeMocks();
  const c = new PledgePageComponent(location as any, router as any);
  c.goBack();
  assertEqual(location.wentBack, true);
});

test('PledgePage: goToAuth navigates to /auth', () => {
  const { location, router } = makeMocks();
  const c = new PledgePageComponent(location as any, router as any);
  c.goToAuth();
  assertEqual(router._navigated.length, 1);
  assertEqual(router._navigated[0][0], '/auth');
});

import { Component } from '@angular/core';
import { CommonModule, Location } from '@angular/common';
import { Router } from '@angular/router';
import { PledgeComponent } from '../pledge/pledge.component';

@Component({
  selector: 'kree-pledge-page',
  standalone: true,
  imports: [CommonModule, PledgeComponent],
  templateUrl: './pledge-page.component.html',
  styleUrls: ['./pledge-page.component.css'],
})
export class PledgePageComponent {
  pledgeComplete = false;

  constructor(
    private location: Location,
    private router: Router,
  ) {}

  goBack(): void {
    this.location.back();
  }

  onPledgeDone(): void {
    this.pledgeComplete = true;
  }

  goToAuth(): void {
    this.router.navigate(['/auth']);
  }
}
